"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[6615],{1598:e=>{e.exports=JSON.parse('{"version":{"pluginId":"examples","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"docsSidebar":[{"type":"link","label":"Examples","href":"/examples/overview/","docId":"overview/index","unlisted":false},{"type":"category","collapsed":false,"label":"Agents","items":[{"type":"link","label":"Adding a tool","href":"/examples/agents/adding_tool","docId":"agents/adding_tool","unlisted":false},{"type":"link","label":"Adding a workflow","href":"/examples/agents/adding_workflow","docId":"agents/adding_workflow","unlisted":false},{"type":"link","label":"Supervisor Agent","href":"/examples/agents/supervisor_agent","docId":"agents/supervisor_agent","unlisted":false},{"type":"link","label":"Image Analysis Agent","href":"/examples/agents/image_analysis","docId":"agents/image_analysis","unlisted":false},{"type":"link","label":"Using Voice with Agents","href":"/examples/agents/using_voice","docId":"agents/using_voice","unlisted":false}],"collapsible":true}]},"docs":{"agents/adding_tool":{"id":"agents/adding_tool","title":"Adding a tool","description":"When building AI agents, you often need to extend their capabilities with external data or functionality. Timbal lets you pass tools to an agent using the tools parameter. Tools give agents a way to call specific functions, such as fetching data or performing calculations, to help answer a user\'s query.","sidebar":"docsSidebar"},"agents/adding_workflow":{"id":"agents/adding_workflow","title":"Adding a workflow","description":"When building AI agents, it can be useful to combine them with workflows that perform multi-step tasks or fetch structured data. Timbal lets you pass workflows to an agent using the workflows parameter. Workflows provide a way for agents to trigger predefined sequences of steps, giving them access to more complex operations than a single tool can provide.","sidebar":"docsSidebar"},"agents/image_analysis":{"id":"agents/image_analysis","title":"Image Analysis Agent","description":"When building AI applications, you often need agents that can analyze and understand visual content. Timbal lets you create image analysis agents that can identify objects, describe scenes, and answer questions about visual content using the tools parameter.","sidebar":"docsSidebar"},"agents/supervisor_agent":{"id":"agents/supervisor_agent","title":"Supervisor Agent","description":"When building complex AI applications, you often need multiple specialized agents to collaborate on different aspects of a task. A supervisor agent enables one agent to act as a supervisor, coordinating the work of other agents, each focused on their own area of expertise. This structure allows agents to delegate, collaborate, and produce more advanced outputs than any single agent alone.","sidebar":"docsSidebar"},"agents/using_voice":{"id":"agents/using_voice","title":"Using Voice with Agents","description":"Giving your Agent a Voice","sidebar":"docsSidebar"},"overview/index":{"id":"overview/index","title":"Examples","description":"","sidebar":"docsSidebar"}}}}')}}]);